package status

import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/go-logr/logr"
	apierrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/types"
	"k8s.io/apimachinery/pkg/util/wait"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/controller"
	ngftypes "github.com/nginx/nginx-gateway-fabric/v2/internal/framework/types"
)

// UpdateRequest is a request to update the status of a resource.
type UpdateRequest struct {
	ResourceType ngftypes.ObjectType
	Setter       Setter
	NsName       types.NamespacedName
}

// Setter is a function that sets the status of the passed resource.
// It returns true if the status was set, false otherwise.
// The status is not set when the status is already up-to-date.
type Setter func(client.Object) (wasSet bool)

// Updater updates the status of resources.
//
// It has the following limitations:
//
// (1) It is synchronous, which means the status reporter can slow down the event loop.
// Consider the following cases:
// (a) Sometimes the Gateway will need to update statuses of all resources it handles, which could be ~1000. Making 1000
// status API calls sequentially will take time.
// (b) k8s API can become slow or even timeout. This will increase every update status API call.
// Making Updater asynchronous will prevent it from adding variable delays to the event loop.
// FIXME(pleshakov): https://github.com/nginx/nginx-gateway-fabric/issues/1014
//
// (2) It doesn't clear the statuses of a resources that are no longer handled by the Gateway. For example, if
// an HTTPRoute resource no longer has the parentRef to the Gateway resources, the Gateway must update the status
// of the resource to remove the status about the removed parentRef.
// FIXME(pleshakov): https://github.com/nginx/nginx-gateway-fabric/issues/1015
//
// (3) If another controllers changes the status of the Gateway/HTTPRoute resource so that the information set by our
// Gateway is removed, our Gateway will not restore the status until the EventLoop invokes the StatusUpdater as a
// result of processing some other new change to a resource(s).
// FIXME(pleshakov): https://github.com/nginx/nginx-gateway-fabric/issues/1813
type Updater struct {
	client client.Client
	logger logr.Logger
}

var ErrFailedAssert = errors.New("type assertion failed")

// NewUpdater creates a new Updater.
func NewUpdater(c client.Client, logger logr.Logger) *Updater {
	return &Updater{
		client: c,
		logger: logger,
	}
}

// Update updates the status of the resources from the requests.
func (u *Updater) Update(ctx context.Context, reqs ...UpdateRequest) {
	for _, r := range reqs {
		select {
		case <-ctx.Done():
			return
		default:
		}

		u.logger.V(1).Info(
			"Updating status for resource",
			"namespace", r.NsName.Namespace,
			"name", r.NsName.Name,
			"kind", r.ResourceType.GetObjectKind().GroupVersionKind().Kind,
		)

		u.writeStatuses(ctx, r.NsName, r.ResourceType, r.Setter)
	}
}

func (u *Updater) writeStatuses(
	ctx context.Context,
	nsname types.NamespacedName,
	resourceType ngftypes.ObjectType,
	statusSetter Setter,
) {
	copiedObject := resourceType.DeepCopyObject()
	obj, ok := copiedObject.(client.Object)
	if !ok {
		panic(fmt.Errorf("object is not a client.Object: %w", ErrFailedAssert))
	}

	err := wait.ExponentialBackoffWithContext(
		ctx,
		wait.Backoff{
			Duration: time.Millisecond * 200,
			Factor:   2,
			Jitter:   0.5,
			Steps:    4,
			Cap:      time.Millisecond * 3000,
		},
		// Function returns true if the condition is satisfied, or an error if the loop should be aborted.
		NewRetryUpdateFunc(u.client, u.client.Status(), nsname, obj, u.logger, statusSetter),
	)
	if err != nil && !errors.Is(err, context.Canceled) {
		u.logger.Error(
			err,
			"Failed to update status",
			"namespace", nsname.Namespace,
			"name", nsname.Name,
			"kind", resourceType.GetObjectKind().GroupVersionKind().Kind)
	}
}

// NewRetryUpdateFunc returns a function which will be used in wait.ExponentialBackoffWithContext.
// The function will attempt to Update a kubernetes resource and will be retried in
// wait.ExponentialBackoffWithContext if an error occurs. Exported for testing purposes.
//
// wait.ExponentialBackoffWithContext will retry if this function returns nil as its error,
// which is what we want if we encounter an error from the functions we call. However,
// the linter will complain if we return nil if an error was found.
//
// Note: this function is public because fake dependencies require us to test this function from the test package
// to avoid import cycles.
func NewRetryUpdateFunc(
	getter controller.Getter,
	updater K8sUpdater,
	nsname types.NamespacedName,
	obj client.Object,
	logger logr.Logger,
	statusSetter Setter,
) func(ctx context.Context) (bool, error) {
	return func(ctx context.Context) (bool, error) {
		// The function handles errors by reporting them in the logs.
		// We need to get the latest version of the resource.
		// Otherwise, the Update status API call can fail.
		// Note: the default client uses a cache for reads, so we're not making an unnecessary API call here.
		// the default is configurable in the Manager options.
		if err := getter.Get(ctx, nsname, obj); err != nil {
			// apierrors.IsNotFound(err) can happen when the resource is deleted,
			// so no need to retry or return an error.
			if apierrors.IsNotFound(err) {
				return true, nil
			}

			logger.V(1).Info(
				"Encountered error when getting resource to update status",
				"error", err,
				"namespace", nsname.Namespace,
				"name", nsname.Name,
				"kind", obj.GetObjectKind().GroupVersionKind().Kind,
			)

			return false, nil
		}

		if !statusSetter(obj) {
			logger.V(1).Info(
				"Skipping status update because there's no change",
				"namespace", nsname.Namespace,
				"name", nsname.Name,
				"kind", obj.GetObjectKind().GroupVersionKind().Kind,
			)

			return true, nil
		}

		if err := updater.Update(ctx, obj); err != nil {
			logger.V(1).Info(
				"Encountered error updating status",
				"error", err,
				"namespace", nsname.Namespace,
				"name", nsname.Name,
				"kind", obj.GetObjectKind().GroupVersionKind().Kind,
			)

			return false, nil
		}

		return true, nil
	}
}

package status

import (
	"context"
	"sync"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/types"
)

// UpdateType is the type of status update to perform.
type UpdateType int

const (
	// UpdateAll means to update statuses of all Gateway API resources.
	UpdateAll = iota
	// UpdateGateway means to just update the status of the Gateway resource.
	UpdateGateway
)

type Deployment struct {
	NamespacedName types.NamespacedName
	GatewayName    string
}

// QueueObject is the object to be passed to the queue for status updates.
type QueueObject struct {
	// GatewayService is the Gateway Service that was updated. When set, UpdateType should be UpdateGateway.
	// Set by the provisioner
	GatewayService *corev1.Service
	Error          error
	Deployment     Deployment
	UpdateType     UpdateType
	// NginxConfigPushed indicates that an NGINX configuration push was attempted for this update.
	// When false the update is a status-only change (e.g. a WAF poll result) and the
	// "NGINX configuration was successfully updated" log should be suppressed.
	NginxConfigPushed bool
}

// Queue represents a queue with unlimited size.
type Queue struct {
	notifyCh chan struct{}
	items    []*QueueObject

	lock sync.Mutex
}

// NewQueue returns a new Queue object.
func NewQueue() *Queue {
	return &Queue{
		items:    []*QueueObject{},
		notifyCh: make(chan struct{}, 1),
	}
}

// Enqueue adds an item to the queue and notifies any blocked readers.
func (q *Queue) Enqueue(item *QueueObject) {
	q.lock.Lock()
	defer q.lock.Unlock()

	q.items = append(q.items, item)

	select {
	case q.notifyCh <- struct{}{}:
	default:
	}
}

// Dequeue removes and returns the front item from the queue.
// It blocks if the queue is empty or when the context is canceled.
func (q *Queue) Dequeue(ctx context.Context) *QueueObject {
	q.lock.Lock()
	defer q.lock.Unlock()

	for len(q.items) == 0 {
		q.lock.Unlock()
		select {
		case <-ctx.Done():
			q.lock.Lock()
			return nil
		case <-q.notifyCh:
			q.lock.Lock()
		}
	}

	front := q.items[0]
	q.items = q.items[1:]

	return front
}

package status

import (
	"context"
	"errors"
	"sync"
)

// GroupUpdater updates statuses of groups of resources.
//
// Note: this interface is created so that it that we can create a fake from it and use it
// in controller/handler_test.go (to avoid import cycles).
//
//counterfeiter:generate . GroupUpdater
type GroupUpdater interface {
	UpdateGroup(ctx context.Context, name string, reqs ...UpdateRequest)
}

// LeaderAwareGroupUpdater updates statuses of groups of resources.
// Before it is enabled, it saves all requests.
// When it is enabled, it updates status using the saved requests. Note: it can only be enabled once.
// After it is enabled, it will not save requests anymore and update statuses immediately.
type LeaderAwareGroupUpdater struct {
	updater   *Updater
	lock      *sync.Mutex
	groupReqs map[string][]UpdateRequest
	enabled   bool
}

// NewLeaderAwareGroupUpdater creates a new LeaderAwareGroupUpdater.
func NewLeaderAwareGroupUpdater(updater *Updater) *LeaderAwareGroupUpdater {
	return &LeaderAwareGroupUpdater{
		updater:   updater,
		lock:      &sync.Mutex{},
		groupReqs: make(map[string][]UpdateRequest),
	}
}

// UpdateGroup updates statuses of a group of resources.
func (u *LeaderAwareGroupUpdater) UpdateGroup(ctx context.Context, name string, reqs ...UpdateRequest) {
	u.lock.Lock()
	defer u.lock.Unlock()

	if !u.enabled {
		if len(reqs) == 0 {
			delete(u.groupReqs, name)
			return
		}

		u.groupReqs[name] = reqs
		return
	}

	u.updater.Update(ctx, reqs...)
}

// Enable enables the LeaderAwareGroupUpdater, updating statuses using the saved requests.
func (u *LeaderAwareGroupUpdater) Enable(ctx context.Context) {
	u.lock.Lock()
	defer u.lock.Unlock()

	if u.enabled {
		panic(errors.New("LeaderAwareGroupUpdater can only be enabled once"))
	}

	u.enabled = true

	for name, reqs := range u.groupReqs {
		u.updater.Update(ctx, reqs...)
		delete(u.groupReqs, name)
	}
}

		return graph.RouteTypeGRPC
	default:
		return ""
	}
}

func (h *eventHandlerImpl) waitForStatusUpdates(ctx context.Context) {
	for {
		item := h.cfg.statusQueue.Dequeue(ctx)
		if item == nil {
			return
		}

		gr := h.cfg.processor.GetLatestGraph()
		if gr == nil {
			continue
		}

		var nginxReloadRes graph.NginxReloadResult
		var gw *graph.Gateway
		if item.Deployment.NamespacedName.Name != "" {
			gwNSName := types.NamespacedName{
				Namespace: item.Deployment.NamespacedName.Namespace,
				Name:      item.Deployment.GatewayName,
			}

			gw = gr.Gateways[gwNSName]
		}

		switch {
		case item.Error != nil:
			h.cfg.logger.Error(item.Error, "Failed to update NGINX configuration")
			nginxReloadRes.Error = item.Error
		case gw != nil && item.NginxConfigPushed:
			h.cfg.logger.Info("NGINX configuration was successfully updated")
		}
		// Only update LatestReloadResult when a config push was actually attempted.
		// Status-only queue items (e.g., WAF poll callbacks) have NginxConfigPushed=false
		// and no error; updating LatestReloadResult for those would incorrectly clear a
		// prior NGINX reload error without any config change having occurred.
		if gw != nil && (item.NginxConfigPushed || item.Error != nil) {
			gw.LatestReloadResult = nginxReloadRes
		}

		switch item.UpdateType {
		case status.UpdateAll:
			h.updateStatuses(ctx, gr, gw)
		case status.UpdateGateway:
			if gw == nil {
				continue
			}

			gwAddresses, err := getGatewayAddresses(
				ctx,
				h.cfg.k8sClient,
				item.GatewayService,
				gw,
				h.cfg.gatewayClassName,
			)
			if err != nil {
				msg := "error getting Gateway Service IP address"
				h.cfg.logger.Error(err, msg)
				h.cfg.eventRecorder.Eventf(
					item.GatewayService,
					gw.Source,
					v1.EventTypeWarning,
					"GetServiceIPFailed",
					"None",
					msg+": %s",
					err.Error(),
				)
			}

			transitionTime := metav1.Now()

			gatewayStatuses := status.PrepareGatewayRequests(
				gw,
				transitionTime,
				gwAddresses,
				gw.LatestReloadResult,
			)
			h.cfg.statusUpdater.UpdateGroup(ctx, groupGateways, gatewayStatuses...)
		default:
			panic(fmt.Sprintf("unknown event type %T", item.UpdateType))
		}
	}
}

func (h *eventHandlerImpl) updateStatuses(ctx context.Context, gr *graph.Graph, gw *graph.Gateway) {
	transitionTime := metav1.Now()
	gcReqs := status.PrepareGatewayClassRequests(gr.GatewayClass, gr.IgnoredGatewayClasses, transitionTime)

	if gw == nil {
		h.cfg.statusUpdater.UpdateGroup(ctx, groupAllExceptGateways, gcReqs...)
		return
	}

	gwAddresses, err := getGatewayAddresses(ctx, h.cfg.k8sClient, nil, gw, h.cfg.gatewayClassName)
	if err != nil {
		msg := "error getting Gateway Service IP address"
		h.cfg.logger.Error(err, msg)
		h.cfg.eventRecorder.Eventf(
			&v1.Service{},
			gw.Source,
			v1.EventTypeWarning,
			"GetServiceIPFailed",
			"None",
			msg+": %s",
			err.Error(),
		)
	}

	routeReqs := status.PrepareRouteRequests(
		gr.L4Routes,
		gr.Routes,
		transitionTime,
		h.cfg.gatewayCtlrName,
	)

	polReqs := status.PrepareBackendTLSPolicyRequests(gr.BackendTLSPolicies, transitionTime, h.cfg.gatewayCtlrName)

	// Merge WAF poll results into policy conditions before preparing status requests.
	// Bundle updates are applied first so that active poll errors can overwrite them
	// during deduplication (conditions are deduplicated by Type, last-write wins).
	h.mergeWAFBundleUpdates(gr)
	h.mergeWAFPollErrors(gr)

	ngfPolReqs := status.PrepareNGFPolicyRequests(gr.NGFPolicies, transitionTime, h.cfg.gatewayCtlrName)
	snippetsFilterReqs := status.PrepareSnippetsFilterRequests(
		gr.SnippetsFilters,
		transitionTime,
		h.cfg.gatewayCtlrName,
	)
	authenticationFilterReqs := status.PrepareAuthenticationFilterRequests(
		gr.AuthenticationFilters,
		transitionTime,
		h.cfg.gatewayCtlrName,
	)
	listenerSetReqs := status.PrepareListenerSetRequests(
		gr.ListenerSets,
		transitionTime,
	)

	// unfortunately, status is not on clusterState stored by the change processor, so we need to make a k8sAPI call here
	ipList := &inference.InferencePoolList{}
	if h.cfg.inferenceExtension {
		err = h.cfg.k8sClient.List(ctx, ipList)
		if err != nil {
			msg := "error listing InferencePools for status update"
			h.cfg.logger.Error(err, msg)
			h.cfg.eventRecorder.Eventf(
				&inference.InferencePoolList{},
				nil,
				v1.EventTypeWarning,
				"ListInferencePoolsFailed",
				"None",
				msg+": %s",
				err.Error(),
			)
			ipList = &inference.InferencePoolList{} // reset to empty list to avoid nil pointer dereference
		}
	}
	inferencePoolReqs := status.PrepareInferencePoolRequests(
		gr.ReferencedInferencePools,
		ipList,
		gr.Gateways,
		transitionTime,
	)

	reqs := make(
		[]status.UpdateRequest,
		0,
		len(gcReqs)+
			len(routeReqs)+
			len(polReqs)+
			len(ngfPolReqs)+
			len(snippetsFilterReqs)+
			len(authenticationFilterReqs)+
			len(listenerSetReqs)+
			len(inferencePoolReqs),
	)
	reqs = append(reqs, gcReqs...)
	reqs = append(reqs, routeReqs...)
	reqs = append(reqs, polReqs...)
	reqs = append(reqs, ngfPolReqs...)
	reqs = append(reqs, snippetsFilterReqs...)
	reqs = append(reqs, authenticationFilterReqs...)
	reqs = append(reqs, listenerSetReqs...)
	reqs = append(reqs, inferencePoolReqs...)

	h.cfg.statusUpdater.UpdateGroup(ctx, groupAllExceptGateways, reqs...)

	// We put Gateway status updates separately from the rest of the statuses because we want to be able
	// to update them separately from the rest of the graph whenever the public IP of NGF changes.
	gwReqs := status.PrepareGatewayRequests(
		gw,
		transitionTime,
		gwAddresses,
		gw.LatestReloadResult,
	)
	h.cfg.statusUpdater.UpdateGroup(ctx, groupGateways, gwReqs...)
}

