			for _, name := range names {
				var gc v1.GatewayClass
				Expect(k8sClient.Get(context.Background(), types.NamespacedName{Name: name}, &gc)).To(Succeed())
				Expect(gc.Status).To(Equal(v1.GatewayClassStatus{}))
			}
